// Extract top 30 gainers and losers
const response = $json;

const gainers = (response.top_gainers || []).slice(0, 30);
const losers = (response.top_losers || []).slice(0, 30);

// Parse stock data
function parseStock(s, type) {
  const pct = parseFloat(String(s.change_percentage || '0').replace('%','')) || 0;
  const vol = parseInt(s.volume) || 0;
  return { 
    ticker: s.ticker, 
    price: parseFloat(s.price) || 0, 
    changePercent: pct, 
    volume: vol, 
    type 
  };
}

// Combine and sort by volume (highest first)
let all = [
  ...gainers.map(s => parseStock(s, 'gainer')), 
  ...losers.map(s => parseStock(s, 'loser'))
];
all = all.sort((a, b) => b.volume - a.volume);

// Get top 10 by volume
const top10 = all.slice(0, 10);

// Return each stock as a separate item for Split in Batches
return top10.map(stock => ({ json: stock }));

// Get stock info from the split batch
const stock = $input.item.json;
const ticker = stock.ticker;

// Get news feed
const news = $json.feed || [];

// Filter news from last 24 hours
const now = new Date();
const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const recentNews = news.filter(article => {
  if (!article.time_published) return false;

  // Parse YYYYMMDDTHHMMSS format
  const year = parseInt(article.time_published.slice(0, 4));
  const month = parseInt(article.time_published.slice(4, 6)) - 1;
  const day = parseInt(article.time_published.slice(6, 8));
  const hour = parseInt(article.time_published.slice(9, 11));
  const minute = parseInt(article.time_published.slice(11, 13));
  const second = parseInt(article.time_published.slice(13, 15));

  const articleDate = new Date(year, month, day, hour, minute, second);
  return articleDate >= twentyFourHoursAgo;
});

// Format news data
let newsData = {};
if (recentNews.length > 0) {
  const first = recentNews[0];
  const raw = first.summary || first.title || "";
  const summary = raw.length > 200 ? raw.slice(0, 200) + "..." : raw;

  newsData = {
    headline: first.title || "",
    summary: summary,
    url: first.url || "",
    publishedTime: first.time_published || "",
    sentiment: first.overall_sentiment_label || "Neutral",
    sentimentScore: first.overall_sentiment_score || 0,
    articlesCount: recentNews.length
  };
} else {
  newsData = {
    headline: "No recent news in last 24h",
    summary: "",
    url: "",
    publishedTime: "",
    sentiment: "N/A",
    sentimentScore: 0,
    articlesCount: 0
  };
}

// Return stock data with news
return {
  ticker: ticker,
  price: stock.price,
  changePercent: stock.changePercent,
  volume: stock.volume,
  type: stock.type,
  news: newsData
};

// Aggregate all results
const results = items.map(item => item.json);

// Sort by volume descending
results.sort((a, b) => b.volume - a.volume);

// Create summary statistics
const gainers = results.filter(s => s.type === 'gainer');
const losers = results.filter(s => s.type === 'loser');
const withNews = results.filter(s => s.news.articlesCount > 0);

const summary = {
  totalStocks: results.length,
  gainersCount: gainers.length,
  losersCount: losers.length,
  stocksWithNews: withNews.length,
  stocksWithoutNews: results.length - withNews.length,
  generatedAt: new Date().toISOString()
};

return [{
  json: {
    summary: summary,
    top10Movers: results
  }
}];
